var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"…그래. 기억을 봉인한 뒤로 참 시간이 많이 흘렀군.","JPN":"……ああ。記憶を封印して、いつの間にかこんなにも時間が経ってしまった。","ENG":"...Yes. Quite a lot of time has passed since I sealed away my memories.","TWN":"……是啊。自從封印記憶之後，真的過了很長一段時間。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"지금은 물안개가 걷힌 것처럼 모든 것이 또렷해. 너와의 맹세, 지난 세계의 기억… 그리고 내가 저버린 신의까지도.","JPN":"今は霧が晴れたようにすべてを鮮明に思い出せる。お前との誓い、過去の世界の記憶……そして私が背いた信頼までも。","ENG":"Now it's all clear again, as if the fog has lifted. The oath we shared, the memories of the previous world... Even the faith I once cast aside.","TWN":"現在，一切都像霧氣散去般清晰。與你的誓言、過去世界的記憶……以及我背棄的神。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"탐미엘을 묶어두기 위해서 필요한 일이었다는 건 알지만, 이 복수심을 잠시나마 망각하고 있었다는 사실이 부끄럽군.","JPN":"タミエルを引き留めるために必要なことだったとはいえ、この復讐心を少しの間でも忘れていたとは恥ずかしい限りだ。","ENG":"I know it was necessary to bind Tammiel. Still, forgetting that vengeance, even for a time, feels shameful.","TWN":"我知道那是為了束縛塔米爾必須做的事，但我竟然一度忘卻了這份復仇的心，實在令人羞愧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"이젠 슬슬 그 녀석과도 담판을 지을 준비를 해야겠지.","JPN":"そろそろあいつと決着をつける準備をしないとな。","ENG":"Soon enough, I'll need to settle things with her properly.","TWN":"也差不多該準備和那傢伙做個了斷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그 전에 먼저, 내가 만들어낸 과오들과 마주해야겠지만 말이야.","JPN":"その前に、まず自分が生み出した過ちと向き合わねばならないが。","ENG":"But before that, I must face the mistakes I created myself.","TWN":"不過在那之前，我得先面對自己一手造成的過錯。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"음? 우리가 처음 만났을 때의 기억도 떠올랐냐고?","JPN":"ん？　初めて出会った時のことも思い出したのかだと？","ENG":"Mm? Do I remember when we first met?","TWN":"嗯？你問我是不是想起我們第一次見面時的記憶？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"…아주 놀려먹을 의도가 다분한 질문을 하는군.","JPN":"……その質問、からかう意図が見え見えだな。","ENG":"...That question is very clearly meant to tease me.","TWN":"……這問題擺明就是想捉弄我吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"흥, 그래. 날 미아로 착각한 네가 내 머리를 쓰다듬어서 그 손목을 접어버렸었지.","JPN":"ふん、思い出したさ。私を迷子と勘違いしたお前が私の頭を撫でるから、その手首をへし折ってやったな。","ENG":"Hmph. I do. You mistook me for a lost child and patted my head, so I bent your wrist in return.","TWN":"哼，是啊。你把我誤認成迷路的小孩摸摸我的頭，結果我直接折斷你的手腕。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그 뒤로도 정신 못 차리고 가벼운 농담 따먹기로 내게 말을 거는 널 자기과신에 빠진 오만한 인간이라 생각한 적도 있었다.","JPN":"その後も、性懲りもなく軽口を叩いてくるお前を、私は自己過信に陥った傲慢なやつだと思っていたこともあった。","ENG":"Even after that, you kept talking to me so casually that I thought you were just another arrogant fool, drunk on your own confidence.","TWN":"之後你還不知反省，用輕浮的玩笑跟我搭話。我一度以為你是個過度自負的傲慢人類。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"뭐, 그건 전부 오해였고 넌 그저 눈치가 좀 부족할 뿐인 좋은 녀석이란 걸- 지금은 알고 있지만 말이야.","JPN":"まあ、あれは全部誤解で、お前は空気を読む能力が少し欠けているだけのいいやつなのだと、今は分かっている。","ENG":"Well, I know now that it was all a misunderstanding and that you're simply a good person who happens to lack tact.","TWN":"不過嘛那些全是誤會。現在我知道了，你只不過是有點不太會看眼色的好人而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그날로부터 시간이 꽤 많이 흘러버렸지만, 지금이라도 고맙단 말을 해두고 싶군.","JPN":"あの日から随分と時が過ぎてしまったが、お礼を言わせてくれ。","ENG":"A great deal of time has passed since then, but I want to say this now. Thank you.","TWN":"雖然從那天起已經過了很久，但我還是想向你道謝。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"날 만난 뒤부터 그 커다란 테라브레인들을 내 키에 맞춰 재설계한 게, 우연이 아니란 것쯤은 알고 있거든.","JPN":"私に出会った以後に、あの巨大なテラブレインが私の身長ぐらいの高さに再設計されたのも、偶然ではないということぐらい気づいている。","ENG":"I know redesigning those massive Terrabrains to match my height after we met wasn't a coincidence.","TWN":"你在遇到我後特地把那些巨大的特拉大腦重新設計成符合我身高的尺寸，我知道那並不是巧合。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그… 오해해서 미안하고, 고맙다.","JPN":"その……誤解して悪かった。そして、ありがとう。","ENG":"So... I'm sorry for the misunderstanding. And thank you.","TWN":"那個……抱歉我誤會你了，還有謝謝你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"…라고 하자마자, 갑자기 쪼그려 앉아서 쳐다볼 생각을 하다니. 참 너답군.","JPN":"……と言ったそばから目線を合わせようとしゃがんでくるあたりがお前らしいな。","ENG":"...And right after that, you squat down to look me in the eye. That's very like you.","TWN":"……我才剛說完，你就突然想到要蹲下來看，真是太像你會做的事了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"뭐…? 복수할 기회를 줄 테니 마음껏 머릴 쓰다듬으라고?","JPN":"何……？　復讐するチャンスをやるから、好きなだけ頭を撫でろ？","ENG":"What...? You'll give me a chance at revenge, so I should pat your head as much as I like?","TWN":"什麼……？說會給我報仇的機會，所以可以盡情摸我的頭？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"하, 정말이지…","JPN":"はあ、まったく……","ENG":"Ugh, honestly...","TWN":"哈，真是的……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"…너답군 그래.","JPN":"……お前らしい。","ENG":"...That's very like you.","TWN":"……果然很像你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};